import{_ as l,o as a,c as s,a9 as e}from"./chunks/framework.STMWz9Nm.js";const o=JSON.parse('{"title":"并发基础与线程安全","description":"","frontmatter":{},"headers":[],"relativePath":"语言/Rust/01-Rust语言基础与核心机制/10-并发基础与线程安全.md","filePath":"语言/Rust/01-Rust语言基础与核心机制/10-并发基础与线程安全.md","lastUpdated":1777177198000}'),t={name:"语言/Rust/01-Rust语言基础与核心机制/10-并发基础与线程安全.md"};function h(r,i,n,d,p,k){return a(),s("div",null,[...i[0]||(i[0]=[e(`<h1 id="并发基础与线程安全" tabindex="-1">并发基础与线程安全 <a class="header-anchor" href="#并发基础与线程安全" aria-label="Permalink to “并发基础与线程安全”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>Rust 的并发基础，核心是在回答两个问题：</p><ul><li>多个执行单元怎样一起工作</li><li>它们共享数据时，怎样避免数据竞争和未定义行为</li></ul><p>在很多语言里，并发问题往往是“程序能跑，但偶尔会错”。<br> 而 Rust 的设计目标之一，就是尽量把这类问题前移到编译期。</p><p>一句话理解：</p><ul><li>并发让程序能同时处理更多事情</li><li>线程安全保证这些“同时进行”的事情不会把数据搞坏</li></ul><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>现代程序很少是完全串行的。你会不断遇到这些场景：</p><ul><li>同时处理多个请求</li><li>后台任务和主逻辑并行执行</li><li>多核 CPU 上分摊计算</li><li>I/O 等待期间不让程序空转</li></ul><p>但并发带来的风险也非常真实：</p><ul><li>两个线程同时改同一份数据</li><li>一个线程读到另一个线程一半写完的数据</li><li>锁顺序错了，程序死锁</li><li>状态同步不清，结果偶现错误</li></ul><p>Rust 对并发的重要价值在于：</p><ul><li>把一部分线程安全问题提前到类型系统和编译器层面</li><li>降低“看起来没问题，线上随机炸”的概率</li></ul><h2 id="_3-先建立直觉" tabindex="-1">3. 先建立直觉 <a class="header-anchor" href="#_3-先建立直觉" aria-label="Permalink to “3. 先建立直觉”">​</a></h2><p>先不要一上来想线程 API，而是先建立一个朴素图景：</p><ul><li><strong>并发</strong>：多件事在时间上交错推进</li><li><strong>并行</strong>：多件事真的在多个核上同时执行</li><li><strong>线程安全</strong>：不管调度顺序如何，数据都不会被破坏</li></ul><p>Rust 看待并发，不只是“怎么开线程”，更是“数据怎么过边界”：</p><ul><li>值是被移动过去</li><li>还是被共享过去</li><li>如果共享，是否还有修改</li><li>如果修改，靠什么约束</li></ul><p>所以 Rust 的并发模型和所有权是连在一起的。</p><h2 id="_4-核心内容" tabindex="-1">4. 核心内容 <a class="header-anchor" href="#_4-核心内容" aria-label="Permalink to “4. 核心内容”">​</a></h2><h3 id="_4-1-并发不只是开线程" tabindex="-1">4.1 并发不只是开线程 <a class="header-anchor" href="#_4-1-并发不只是开线程" aria-label="Permalink to “4.1 并发不只是开线程”">​</a></h3><p>很多初学者一说并发就想到：</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">std</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">thread</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">spawn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>但真正困难的往往不是“开线程”，而是：</p><ul><li>线程之间怎么传数据</li><li>共享状态怎么控制</li><li>生命周期和所有权怎么满足</li><li>程序退出时谁先结束</li></ul><p>所以并发学习的重点不应该只是 API，而应该是：<strong>数据和任务之间的关系</strong>。</p><h3 id="_4-2-rust-为什么强调数据竞争" tabindex="-1">4.2 Rust 为什么强调数据竞争 <a class="header-anchor" href="#_4-2-rust-为什么强调数据竞争" aria-label="Permalink to “4.2 Rust 为什么强调数据竞争”">​</a></h3><p>数据竞争可以粗略理解成：</p><ul><li>多个线程访问同一份内存</li><li>至少有一个在写</li><li>又缺乏正确同步</li></ul><p>这类 bug 很可怕，因为它通常：</p><ul><li>不稳定</li><li>难复现</li><li>修起来非常痛苦</li></ul><p>Rust 的强项在于，它会通过所有权、借用以及 <code>Send</code> / <code>Sync</code> 等规则，尽量让很多不安全共享方式在编译期就过不去。</p><h3 id="_4-3-两种常见思路-消息传递-vs-共享状态" tabindex="-1">4.3 两种常见思路：消息传递 vs 共享状态 <a class="header-anchor" href="#_4-3-两种常见思路-消息传递-vs-共享状态" aria-label="Permalink to “4.3 两种常见思路：消息传递 vs 共享状态”">​</a></h3><p>Rust 并发里，最常见的两条路是：</p><h4 id="路线一-消息传递" tabindex="-1">路线一：消息传递 <a class="header-anchor" href="#路线一-消息传递" aria-label="Permalink to “路线一：消息传递”">​</a></h4><p>直觉上像：</p><ul><li>每个线程处理自己的状态</li><li>通过通道把结果发出去</li><li>尽量少共享同一份可变数据</li></ul><p>这条路的好处是边界清楚，往往更容易维护。</p><h4 id="路线二-共享状态" tabindex="-1">路线二：共享状态 <a class="header-anchor" href="#路线二-共享状态" aria-label="Permalink to “路线二：共享状态”">​</a></h4><p>直觉上像：</p><ul><li>多个线程都能访问同一份数据</li><li>但要通过锁或其他同步手段控制访问</li></ul><p>这条路更接近很多传统后端程序写法，但复杂度也更高。</p><p>Rust 里通常会优先鼓励你先思考：<strong>能不能先用消息传递，而不是直接共享可变状态</strong>。</p><h3 id="_4-4-线程之间的数据移动" tabindex="-1">4.4 线程之间的数据移动 <a class="header-anchor" href="#_4-4-线程之间的数据移动" aria-label="Permalink to “4.4 线程之间的数据移动”">​</a></h3><p>Rust 创建线程时，经常会把值 move 进去：</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> data </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> vec!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">];</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">std</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">thread</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">spawn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">move</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ||</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    println!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;{:?}&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, data);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">});</span></span></code></pre></div><p>这里的核心是：</p><ul><li>新线程拿到数据所有权</li><li>原线程不再继续使用那份值</li></ul><p>这很符合 Rust 的一贯思路：</p><ul><li>与其让两个线程都碰同一份可变值</li><li>不如把值明确交给某一个线程</li></ul><p>这其实是在通过所有权减少并发复杂度。</p><h3 id="_4-5-什么是-send-和-sync" tabindex="-1">4.5 什么是 <code>Send</code> 和 <code>Sync</code> <a class="header-anchor" href="#_4-5-什么是-send-和-sync" aria-label="Permalink to “4.5 什么是 Send 和 Sync”">​</a></h3><p>初学 Rust 并发时，经常会碰到 <code>Send</code>、<code>Sync</code> 相关报错。<br> 可以先这样理解：</p><ul><li><code>Send</code>：一个值是否可以安全地在线程之间转移所有权</li><li><code>Sync</code>：一个值是否可以安全地被多个线程共享引用</li></ul><p>不要急着背非常正式的定义，先记住它们是在描述：</p><ul><li>这个类型跨线程是否安全</li><li>这个类型被共享引用时是否安全</li></ul><p>这两个 trait 是 Rust 并发安全体系里非常关键的底层规则。</p><h3 id="_4-6-共享状态常见组合-arc-mutex-t" tabindex="-1">4.6 共享状态常见组合：<code>Arc&lt;Mutex&lt;T&gt;&gt;</code> <a class="header-anchor" href="#_4-6-共享状态常见组合-arc-mutex-t" aria-label="Permalink to “4.6 共享状态常见组合：Arc&lt;Mutex&lt;T&gt;&gt;”">​</a></h3><p>如果多个线程要共同访问并修改同一份数据，最常见的组合就是：</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Arc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Mutex</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">T</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&gt;</span></span></code></pre></div><p>可以拆开理解：</p><ul><li><code>Arc</code>：多个线程共享所有权</li><li><code>Mutex</code>：同一时刻只允许一个线程修改</li></ul><p>它常见，是因为它直观、通用，而且很好地把两个需求分开了：</p><ul><li>共享</li><li>同步</li></ul><p>当然，它不是“并发万金油”。如果使用不当，也会带来锁竞争和死锁风险。</p><h3 id="_4-7-为什么锁不是免费午餐" tabindex="-1">4.7 为什么锁不是免费午餐 <a class="header-anchor" href="#_4-7-为什么锁不是免费午餐" aria-label="Permalink to “4.7 为什么锁不是免费午餐”">​</a></h3><p>很多人从别的语言转到 Rust，会下意识觉得：</p><ul><li>有锁就安全了</li><li>有 <code>Mutex</code> 就万事大吉了</li></ul><p>其实锁只是把问题从“无控制共享”变成“受控制共享”。<br> 它能解决数据竞争，但还可能引入新的问题：</p><ul><li>锁持有时间太长</li><li>不同锁获取顺序不一致</li><li>频繁加锁导致性能差</li><li>把本可拆开的状态硬塞进一把大锁里</li></ul><p>所以更成熟的并发思路通常是：</p><ul><li>先尽量减少共享</li><li>必须共享时再上锁</li><li>上锁后尽量缩小临界区</li></ul><h3 id="_4-8-不可变共享往往比可变共享容易" tabindex="-1">4.8 不可变共享往往比可变共享容易 <a class="header-anchor" href="#_4-8-不可变共享往往比可变共享容易" aria-label="Permalink to “4.8 不可变共享往往比可变共享容易”">​</a></h3><p>并发里最危险的通常不是“大家都在读”，而是“有人在写”。<br> 所以一个很实用的工程判断是：</p><ul><li>如果能把共享数据设计成不可变</li><li>或者改成消息传递更新</li><li>往往比多线程共享可变状态更稳</li></ul><p>这一点非常 Rust，也非常工程化。</p><h3 id="_4-9-线程安全不等于逻辑正确" tabindex="-1">4.9 线程安全不等于逻辑正确 <a class="header-anchor" href="#_4-9-线程安全不等于逻辑正确" aria-label="Permalink to “4.9 线程安全不等于逻辑正确”">​</a></h3><p>Rust 可以帮你避免很多内存层面的并发错误，<br> 但它不能自动保证业务逻辑一定正确。</p><p>比如：</p><ul><li>你的加锁范围不对</li><li>更新顺序不符合业务要求</li><li>两个线程之间虽然没有数据竞争，但整体状态仍然不一致</li></ul><p>所以要记住：</p><ul><li>Rust 能强力约束底层安全</li><li>但高层并发设计仍然需要你自己想清楚</li></ul><h2 id="_5-常见误区" tabindex="-1">5. 常见误区 <a class="header-anchor" href="#_5-常见误区" aria-label="Permalink to “5. 常见误区”">​</a></h2><h3 id="_5-1-误区一-并发就是多开线程" tabindex="-1">5.1 误区一：并发就是多开线程 <a class="header-anchor" href="#_5-1-误区一-并发就是多开线程" aria-label="Permalink to “5.1 误区一：并发就是多开线程”">​</a></h3><p>不完整。<br> 并发真正难的是任务协调和数据边界，而不是“线程数量”。</p><h3 id="_5-2-误区二-只要编译通过-并发逻辑就一定没问题" tabindex="-1">5.2 误区二：只要编译通过，并发逻辑就一定没问题 <a class="header-anchor" href="#_5-2-误区二-只要编译通过-并发逻辑就一定没问题" aria-label="Permalink to “5.2 误区二：只要编译通过，并发逻辑就一定没问题”">​</a></h3><p>不是。<br> Rust 主要帮你约束内存安全和线程安全的一部分问题，业务级并发正确性仍要自己设计。</p><h3 id="_5-3-误区三-arc-mutex-t-是万能解法" tabindex="-1">5.3 误区三：<code>Arc&lt;Mutex&lt;T&gt;&gt;</code> 是万能解法 <a class="header-anchor" href="#_5-3-误区三-arc-mutex-t-是万能解法" aria-label="Permalink to “5.3 误区三：Arc&lt;Mutex&lt;T&gt;&gt; 是万能解法”">​</a></h3><p>它很常见，但不意味着所有共享问题都该这样建模。<br> 有时通道或任务隔离会更合适。</p><h3 id="_5-4-误区四-锁只是性能问题-不影响设计" tabindex="-1">5.4 误区四：锁只是性能问题，不影响设计 <a class="header-anchor" href="#_5-4-误区四-锁只是性能问题-不影响设计" aria-label="Permalink to “5.4 误区四：锁只是性能问题，不影响设计”">​</a></h3><p>错误。<br> 锁的引入会改变模块边界、访问方式和状态组织，本质上是设计问题，不只是性能细节。</p><h2 id="_6-一个更实用的判断思路" tabindex="-1">6. 一个更实用的判断思路 <a class="header-anchor" href="#_6-一个更实用的判断思路" aria-label="Permalink to “6. 一个更实用的判断思路”">​</a></h2><p>写 Rust 并发代码时，可以先这样判断：</p><ol><li>这件事真的要并发吗</li><li>能不能把任务拆开，各自拥有自己的数据</li><li>线程之间是传消息更合适，还是共享状态更合适</li><li>如果必须共享，是否能只共享不可变数据</li><li>如果必须共享可变数据，锁的粒度能不能做小</li><li>当前类型跨线程是否满足 <code>Send</code> / <code>Sync</code> 语义</li></ol><p>按这个顺序想，通常比一上来就堆 <code>Arc&lt;Mutex&lt;_&gt;&gt;</code> 更稳。</p><h2 id="_7-学习建议" tabindex="-1">7. 学习建议 <a class="header-anchor" href="#_7-学习建议" aria-label="Permalink to “7. 学习建议”">​</a></h2><p>建议按下面顺序学习 Rust 并发：</p><ol><li>先理解线程创建与 <code>move</code> 捕获</li><li>再理解消息传递的思路</li><li>再学习 <code>Arc&lt;T&gt;</code>、<code>Mutex&lt;T&gt;</code>、<code>RwLock&lt;T&gt;</code> 的组合</li><li>再理解 <code>Send</code>、<code>Sync</code> 报错在表达什么</li><li>最后进入线程池、异步运行时和更高层的并发框架</li></ol><p>这样可以先把“线程安全”的底层模型建立起来，再进入 Tokio 等更复杂的抽象层。</p><h2 id="_8-自测标准" tabindex="-1">8. 自测标准 <a class="header-anchor" href="#_8-自测标准" aria-label="Permalink to “8. 自测标准”">​</a></h2><ul><li>能区分并发和并行的大致含义</li><li>能解释 Rust 为什么把并发和所有权强绑定</li><li>能说清消息传递和共享状态的基本差异</li><li>能大致理解 <code>Send</code> 与 <code>Sync</code> 在表达什么</li><li>能看懂 <code>Arc&lt;Mutex&lt;T&gt;&gt;</code> 这种组合的大致意图</li><li>能意识到“线程安全”不等于“业务逻辑天然正确”</li></ul>`,102)])])}const u=l(t,[["render",h]]);export{o as __pageData,u as default};
